+        private void TestLiquiditySignals()
+        {
+            OracleLog.Write("SELF_TEST", ">>> TESTING LIQUIDITY SIGNALS");
+
+            // 1. Null state
+            currentLiquidity = null;
+            bool res1 = HasConfirmedSellSideRejectionSweep();
+            OracleLog.Write("SELF_TEST", $"Liquidity 1 (Null): Result={res1} (Expected: False)");
+
+            // 2. No sweep
+            currentLiquidity = new LiquiditySnapshot { LastSweep = null };
+            bool res2 = HasConfirmedSellSideRejectionSweep();
+            OracleLog.Write("SELF_TEST", $"Liquidity 2 (No Sweep): Result={res2} (Expected: False)");
+
+            // 3. Wrong EventType
+            currentLiquidity = new LiquiditySnapshot
+            {
+                LastSweep = new LiquiditySweepSignal
+                {
+                    IsValid = true,
+                    EventType = LiquidityEventType.AcceptedSweep,
+                    SweptSide = LiquiditySide.SellSide
+                }
+            };
+            bool res3 = HasConfirmedSellSideRejectionSweep();
+            OracleLog.Write("SELF_TEST", $"Liquidity 3 (Wrong Event): Result={res3} (Expected: False)");
+
+            // 4. Wrong Side
+            currentLiquidity = new LiquiditySnapshot
+            {
+                LastSweep = new LiquiditySweepSignal
+                {
+                    IsValid = true,
+                    EventType = LiquidityEventType.RejectionSweep,
+                    SweptSide = LiquiditySide.BuySide
+                }
+            };
+            bool res4 = HasConfirmedSellSideRejectionSweep();
+            OracleLog.Write("SELF_TEST", $"Liquidity 4 (Wrong Side): Result={res4} (Expected: False)");
+
+            // 5. Invalid Signal
+            currentLiquidity = new LiquiditySnapshot
+            {
+                LastSweep = new LiquiditySweepSignal
+                {
+                    IsValid = false,
+                    EventType = LiquidityEventType.RejectionSweep,
+                    SweptSide = LiquiditySide.SellSide
+                }
+            };
+            bool res5 = HasConfirmedSellSideRejectionSweep();
+            OracleLog.Write("SELF_TEST", $"Liquidity 5 (Invalid): Result={res5} (Expected: False)");
+
+            // 6. Valid SellSide Rejection Sweep (Happy Path)
+            currentLiquidity = new LiquiditySnapshot
+            {
+                LastSweep = new LiquiditySweepSignal
+                {
+                    IsValid = true,
+                    EventType = LiquidityEventType.RejectionSweep,
+                    SweptSide = LiquiditySide.SellSide
+                }
+            };
+            bool res6 = HasConfirmedSellSideRejectionSweep();
+            OracleLog.Write("SELF_TEST", $"Liquidity 6 (Valid Sell Rejection): Result={res6} (Expected: True)");
+        }
     }
